DDRB  &= ~(1 << PB0);        // PB0 als Eingang
PORTB |=  (1 << PB0);        // internen Pull-Up aktivieren (kein externer R nötig!)

if (!(PINB & (1 << PB0))) {  // ACHTUNG: gedrückt = 0 -> deshalb die Negation!
  // Taster ist gedrückt
}

void setup() {
    // Wir legen eine Variable 'n' an und geben ihr den Wert 7.
    // Das System legt 'n' an einer freien Speicheradresse ab (hier: 0x08F2).
    int n = 7; 

    // Wir erstellen einen Zeiger 'p'.
    // Das '&'-Zeichen holt die Adresse von 'n' (also 0x08F2). 
    // Diese Adresse wird als Inhalt im Zeiger 'p' gespeichert.
    // (Der Zeiger 'p' selbst liegt auf einer eigenen Adresse, z.B. 0x08F4).
    int* p = &n; 

    // Wenn wir jetzt den Wert ändern wollen, auf den 'p' zeigt, 
    // nutzen wir den Stern (*). Folgender Befehl ändert den Inhalt 
    // an der Adresse 0x08F2 von 7 auf 10:
    *p = 10; 

    p++;
}

bloecke.simulation:
const sp = Speicher(0x08F2);

sp.int("n", 7);
sp.ptr("p", "n");
sp.tabelle("int n = 7;  int *p = &n;");

sp.deref("p", 10);
sp.tabelle("nach  *p = 10;   (n wurde über den Zeiger geändert!)");

sp.inc("p");
sp.tabelle("nach  p++;   (Adresse in p ist um 2 Byte gesprungen)");

console.log("n =", sp.wert("n"), "— geändert, ohne n direkt anzufassen!");

