// ── Variante 1: POLLING ────────────────────────────────
void loop() {
  // CPU prüft in JEDEM Schleifendurchlauf den Pin-Zustand.
  if (!(PINB & (1 << PB0))) {   // gedrückt = 0 (Pull-Up!)
    PINB |= (1 << PB5);         // LED toggeln
    _delay_ms(200);             // primitive "Entprellung"
  }
  // Problem: Ist die CPU gerade beschäftigt, kann ein
  // kurzer Tastendruck komplett verloren gehen.
}

// ── Variante 2: INTERRUPT ──────────────────────────────
void setup() {
  DDRB  &= ~(1 << PB0);      // PB0 als Eingang
  PORTB |=  (1 << PB0);      // Pull-Up aktivieren
  DDRB  |=  (1 << PB5);      // PB5 (LED) als Ausgang

  PCICR  |= (1 << PCIE0);    // 1. Pin-Change-Interrupts für Port B aktivieren
  PCMSK0 |= (1 << PCINT0);   // 2. Maskierung: nur PB0 darf auslösen
  sei();                     // 4. Globale Freigabe (I-Bit im SREG)
}

ISR(PCINT0_vect) {           // 3. ISR-Definition
  PINB |= (1 << PB5);        // LED toggeln
}

void loop() {
  // CPU kann hier andere Arbeit erledigen oder schlafen –
  // der Tastendruck wird trotzdem garantiert registriert.
}

uint8_t zaehler(void) {
  static uint8_t count = 0;  // static: Wert überlebt den Funktionsaufruf,
  count++;                   // liegt im RAM, NICHT auf dem Stack
  return count;
}

void setup() {
  uint8_t a = 5;             // a liegt an z.B. Adresse 0x0110, Wert 5
  uint8_t* p = &a;           // p speichert die Adresse 0x0110

  *p = *p + 3;               // Wert AN der Adresse ändern: a ist jetzt 8

  uint8_t x = zaehler();     // x = 1
  x = zaehler();             // x = 2 (count hat sich den Wert 1 gemerkt!)

  DDRB = 0x00;               // kompletten Port B als Eingang
  DDRB |= (1 << PB3);        // nur PB3 als Ausgang  -> DDRB = 0b00001000
  PORTB = 0xAA;              // 0b10101010: PB3 ist Ausgang -> High;
                             // alle anderen Pins mit 1 sind Eingänge
                             // -> dort wird der Pull-Up aktiviert!
}
// Endzustand: a = 8, x = 2, DDRB = 0x08, PORTB = 0xAA
